// 자동 생성 (build-glossary-data workflow). 직접 편집 금지.
export const GLOSSARY_I18N = {"en":{"terms":[{"key":"iq","term":"IQ (Intelligence Quotient)","def":"IQ is a standardized score that summarizes general cognitive ability relative to the population. Scores are set to a mean of 100 and a standard deviation of 15, so 100 is exactly average."},{"key":"deviation-iq","term":"Deviation IQ","def":"Deviation IQ is the modern way of computing IQ as 100 + 15 × z, comparing you against same-age peers rather than using a mental-age formula. It replaced the older ratio IQ and is what every major test uses today."},{"key":"ratio-iq","term":"Ratio IQ","def":"Ratio IQ is the historical method that divided a child's mental age by chronological age and multiplied by 100. It worked for children but broke down for adults, so it was replaced by the deviation IQ."},{"key":"g-factor","term":"General Intelligence (g)","def":"The g factor is the single common ability that underlies performance across virtually all cognitive tasks. Because mental tests tend to correlate positively, g is treated as the core of what IQ measures."},{"key":"fluid-intelligence","term":"Fluid Intelligence (Gf)","def":"Fluid intelligence is the ability to reason, spot patterns, and solve novel problems without relying on prior knowledge. It peaks in the early-to-mid 20s and gradually declines thereafter."},{"key":"crystallized-intelligence","term":"Crystallized Intelligence (Gc)","def":"Crystallized intelligence is accumulated knowledge, vocabulary, and learned skills. Unlike fluid intelligence, it keeps rising well into your 60s as experience builds."},{"key":"percentile","term":"Percentile","def":"A percentile tells you the percentage of people who score at or below your level. An IQ at the 98th percentile means you scored higher than 98% of the population."},{"key":"standard-deviation","term":"Standard Deviation (SD)","def":"Standard deviation measures how spread out scores are around the mean. On the Wechsler scale the IQ standard deviation is 15, so most people fall between 85 and 115."},{"key":"normal-distribution","term":"Normal Distribution (Bell Curve)","def":"The normal distribution is the symmetric bell-shaped curve that IQ scores follow, with most people clustered near the mean and few at the extremes. It lets any score be translated directly into a percentile."},{"key":"mean","term":"Mean (Average)","def":"The mean is the arithmetic average of all scores. For IQ the mean is fixed at 100 by definition, marking the center of the distribution."},{"key":"standardization","term":"Standardization (Norming)","def":"Standardization is the process of administering a test to a large, representative sample to set the norms against which everyone else is scored. It is what makes 100 the true population average."},{"key":"age-norming","term":"Age Norming","def":"Age norming scores you against people of your own age group rather than against everyone. This keeps the average at 100 for every age, which is why raw fluid-reasoning ability can fall while your age-adjusted IQ stays stable."},{"key":"reliability","term":"Reliability","def":"Reliability is how consistently a test produces the same result on repeat measurement. It is often reported as Cronbach's alpha, where good cognitive tests typically score 0.85 or higher."},{"key":"validity","term":"Validity","def":"Validity is whether a test actually measures what it claims to measure. A test can be highly reliable yet still lack validity if it predicts the wrong things."},{"key":"raven-matrices","term":"Raven's Progressive Matrices","def":"Raven's Progressive Matrices is a nonverbal test in which you complete a visual pattern by choosing the missing piece. It is one of the purest measures of fluid intelligence and the g factor because it relies on reasoning rather than language or learned knowledge."},{"key":"chc-theory","term":"CHC Theory (Cattell–Horn–Carroll)","def":"CHC theory is the leading scientific model of cognitive abilities, organizing intelligence into a general g factor over broad abilities like fluid reasoning, comprehension-knowledge, and processing speed. Most modern IQ tests are built around its framework."},{"key":"wechsler","term":"Wechsler Scales (WAIS / WISC)","def":"The Wechsler scales are the clinical gold-standard IQ tests, with the WAIS for adults and the WISC for children. They use a standard deviation of 15 and are administered individually by trained professionals."},{"key":"stanford-binet","term":"Stanford–Binet","def":"The Stanford–Binet is one of the earliest standardized IQ tests and is still in use today. It traditionally uses a standard deviation of 16 rather than the Wechsler 15, so identical scores can differ slightly between the two."},{"key":"mensa","term":"Mensa","def":"Mensa is the best-known high-IQ society, open to anyone who scores at or above the 98th percentile, the top 2%. That threshold corresponds to roughly an IQ of 130 on a standard-deviation-15 scale."},{"key":"flynn-effect","term":"Flynn Effect","def":"The Flynn effect is the steady rise in average IQ test performance over the 20th century, on the order of about 3 points per decade. Because tests are periodically re-normed, the population mean is reset back to 100."},{"key":"gifted","term":"Gifted","def":"Gifted typically refers to an IQ of about 130 or above, placing a person in roughly the top 2% of the population. It is the same threshold used for Mensa eligibility."},{"key":"working-memory","term":"Working Memory","def":"Working memory is the ability to hold and manipulate information in mind for a few seconds, such as keeping numbers in your head while calculating. It is closely linked to fluid reasoning and is a core component in modern IQ models."},{"key":"processing-speed","term":"Processing Speed","def":"Processing speed is how quickly you can perform simple, routine cognitive tasks accurately. It is one of the broad abilities in CHC theory and contributes to overall IQ, especially on timed tests."},{"key":"intellectual-disability","term":"Intellectual Disability","def":"Intellectual disability is defined by significantly below-average intelligence, an IQ around 70 or below, combined with limitations in everyday adaptive skills. Both the score and real-world functioning must be considered, not the number alone."}],"title":"IQ Glossary & Terms","sub":"Plain-English definitions of the key IQ and intelligence terms used across this site."},"ko":{"terms":[{"key":"iq","term":"지능지수(IQ)","def":"지능지수(IQ)는 표준화된 검사로 측정한 인지 능력 점수로, 평균 100, 표준편차 15가 되도록 설계됩니다. 같은 또래 집단과 비교해 상대적 위치를 나타내는 표준화된 지표입니다."},{"key":"deviation-iq","term":"편차지능지수(편차 IQ)","def":"편차 IQ는 같은 연령대 집단 내에서의 표준점수(z)를 이용해 100 + 15×z로 계산하는 현대식 IQ 산출 방식입니다. 과거의 비율 IQ(정신연령 방식)를 대체하여 오늘날 거의 모든 검사에서 사용됩니다."},{"key":"ratio-iq","term":"비율지능지수(비율 IQ)","def":"비율 IQ는 정신연령을 생활연령으로 나눈 뒤 100을 곱해 구하는 초기의 IQ 산출 방식으로, 주로 아동에게 쓰였습니다. 성인에게는 잘 맞지 않아 현재는 편차 IQ로 대체되었습니다."},{"key":"g-factor","term":"일반지능(g 요인)","def":"g 요인은 여러 인지 과제의 성적에 공통으로 작용하는 일반지능을 뜻합니다. 서로 다른 능력 검사 점수들이 함께 높거나 낮게 나타나는 경향을 설명하는 핵심 개념입니다."},{"key":"fluid-intelligence","term":"유동성 지능(Gf)","def":"유동성 지능(Gf)은 사전 지식 없이 새로운 문제를 추론하고 패턴을 파악하는 능력입니다. 20대 초·중반에 정점을 찍은 뒤 서서히 감소하는 것으로 알려져 있습니다."},{"key":"crystallized-intelligence","term":"결정성 지능(Gc)","def":"결정성 지능(Gc)은 학습과 경험으로 쌓은 어휘·지식·이해력을 뜻합니다. 유동성 지능과 달리 60대까지도 꾸준히 향상되는 경향이 있습니다."},{"key":"percentile","term":"백분위","def":"백분위는 자신과 같거나 낮은 점수를 받은 사람의 비율을 백분율로 나타낸 값입니다. 예를 들어 90번째 백분위는 전체의 90%보다 점수가 높다는, 곧 상위 10%라는 뜻입니다."},{"key":"standard-deviation","term":"표준편차","def":"표준편차는 점수가 평균에서 얼마나 퍼져 있는지를 나타내는 값입니다. 웩슬러 척도의 IQ 표준편차는 15로, 100점에서 15점 단위로 멀어질수록 드물어집니다."},{"key":"normal-distribution","term":"정규분포(종형 곡선)","def":"정규분포는 평균을 중심으로 좌우 대칭을 이루는 종 모양의 곡선으로, 대부분의 점수가 평균 부근에 몰립니다. IQ는 이 정규분포를 따르도록 설계되어 평균 100 부근에 사람이 가장 많이 분포합니다."},{"key":"mean","term":"평균","def":"평균은 전체 점수를 더해 인원수로 나눈 대푯값입니다. IQ는 정의상 평균이 정확히 100으로 맞춰져 있어, 100점은 분포의 한가운데인 50번째 백분위에 해당합니다."},{"key":"standardization","term":"표준화","def":"표준화는 검사를 대규모의 대표성 있는 표본에 시행해 점수 기준(규준)을 정하는 과정입니다. 이 과정을 통해 평균 100·표준편차 15 같은 기준이 설정되고 개인 점수를 비교할 수 있게 됩니다."},{"key":"age-norming","term":"연령 규준화","def":"연령 규준화는 같은 연령대 사람들과 비교해 점수를 매기는 방식으로, 모든 연령에서 평균이 100이 되도록 맞춥니다. 덕분에 나이가 들어도 또래 기준의 상대적 위치로 IQ를 해석할 수 있습니다."},{"key":"reliability","term":"신뢰도","def":"신뢰도는 같은 검사를 반복했을 때 결과가 얼마나 일관되게 나오는지를 나타냅니다. 흔히 크론바흐 알파(Cronbach's α) 같은 지표로 평가하며, 값이 높을수록 측정이 안정적입니다."},{"key":"validity","term":"타당도","def":"타당도는 검사가 측정하고자 하는 능력을 실제로 제대로 재고 있는지를 뜻합니다. 신뢰도가 높아도 타당도가 낮으면 엉뚱한 것을 일관되게 재는 셈이 됩니다."},{"key":"raven-matrices","term":"레이븐 누진행렬 검사","def":"레이븐 누진행렬은 도형 패턴의 규칙을 찾아 빈칸을 채우는 비언어 추론 검사입니다. 언어·문화의 영향을 덜 받으며 유동성 지능(g)을 측정하는 대표적 도구입니다."},{"key":"chc-theory","term":"CHC 이론(캐텔-혼-캐럴 이론)","def":"CHC 이론은 캐텔, 혼, 캐럴의 연구를 통합한 인지 능력 모형으로, 오늘날 가장 널리 받아들여지는 지능 이론입니다. 일반지능(g) 아래에 유동성·결정성 지능 등 여러 능력을 위계적으로 배치합니다."},{"key":"wechsler","term":"웩슬러 검사(WAIS·WISC)","def":"웩슬러 검사는 성인용 WAIS와 아동용 WISC로 구성된 임상 표준의 개인 지능검사입니다. 표준편차 15를 사용하며 전문가가 시행하는 가장 신뢰받는 IQ 검사로 꼽힙니다."},{"key":"stanford-binet","term":"스탠퍼드-비네 검사","def":"스탠퍼드-비네 검사는 가장 초기의 표준화 지능검사 중 하나로 현재도 사용됩니다. 웩슬러와 달리 표준편차 16을 사용해 같은 점수라도 해석이 조금 달라집니다."},{"key":"mensa","term":"멘사","def":"멘사는 IQ 상위 2%(98번째 백분위) 이상에게 가입 자격을 주는 국제 고지능자 단체입니다. 일반적인 검사 기준으로 IQ 130 이상이 가입선에 해당합니다."},{"key":"flynn-effect","term":"플린 효과","def":"플린 효과는 20세기 동안 세대가 지날수록 평균 IQ 점수가 꾸준히 상승한 현상입니다. 대략 10년에 약 3점씩 오른 것으로 보고되어 검사 규준을 주기적으로 갱신하는 근거가 됩니다."},{"key":"gifted","term":"영재(우수)","def":"영재는 일반적으로 IQ 130 이상, 곧 상위 약 2%에 드는 경우를 가리킵니다. 멘사 가입선과 같은 수준으로, 통계적으로 50명 중 1명꼴로 나타납니다."},{"key":"working-memory","term":"작업기억","def":"작업기억은 정보를 잠시 머릿속에 붙들고 동시에 조작하는 능력입니다. 유동성 추론과 밀접하게 연관되어 IQ 검사에서 중요한 인지 요소로 다뤄집니다."},{"key":"processing-speed","term":"처리 속도","def":"처리 속도는 단순한 인지 과제를 얼마나 빠르게 수행하는지를 나타내는 능력입니다. 웩슬러 검사 등에서 측정하는 핵심 지표 중 하나로, 빠를수록 정보를 신속히 다룹니다."},{"key":"intellectual-disability","term":"지적장애","def":"지적장애는 IQ가 평균보다 현저히 낮은(대략 70 이하) 동시에 일상 적응 능력에도 제약이 있는 상태를 말합니다. IQ 점수만이 아니라 적응 기능 평가를 함께 고려해 진단합니다."}],"title":"IQ 용어사전","sub":"IQ와 지능 검사에서 자주 쓰이는 핵심 용어를 쉽게 풀이했습니다."},"de":{"terms":[{"key":"iq","term":"Intelligenzquotient (IQ)","def":"Der IQ ist ein standardisierter Messwert für die kognitive Leistungsfähigkeit, normiert auf einen Mittelwert von 100 und eine Standardabweichung von 15. Er zeigt, wie jemand im Vergleich zur Allgemeinbevölkerung abschneidet."},{"key":"deviation-iq","term":"Abweichungs-IQ","def":"Der moderne IQ wird als Abweichungs-IQ berechnet: 100 + 15 × z, wobei z die Standardabweichung vom Durchschnitt der Gleichaltrigen ist. Dieses Verfahren hat den älteren Quotienten-IQ vollständig abgelöst."},{"key":"ratio-iq","term":"Quotienten-IQ","def":"Der historische Quotienten-IQ ergibt sich aus Intelligenzalter geteilt durch Lebensalter, multipliziert mit 100. Er wurde vor allem bei Kindern verwendet, gilt heute aber als überholt und wurde durch den Abweichungs-IQ ersetzt."},{"key":"g-factor","term":"Generalfaktor (g)","def":"Der Generalfaktor g steht für die allgemeine Intelligenz, also den gemeinsamen Kern, der allen kognitiven Fähigkeiten zugrunde liegt. Menschen, die in einem Test gut abschneiden, neigen dazu, auch in anderen gut abzuschneiden – dieses Muster fasst g zusammen."},{"key":"fluid-intelligence","term":"Fluide Intelligenz (Gf)","def":"Die fluide Intelligenz (Gf) ist die Fähigkeit, neue Probleme logisch zu lösen, ohne auf Vorwissen angewiesen zu sein. Sie erreicht ihren Höhepunkt im frühen bis mittleren Erwachsenenalter (etwa Anfang bis Mitte 20)."},{"key":"crystallized-intelligence","term":"Kristalline Intelligenz (Gc)","def":"Die kristalline Intelligenz (Gc) umfasst angesammeltes Wissen, Wortschatz und erlernte Fertigkeiten. Anders als die fluide Intelligenz steigt sie über das Leben hinweg an und bleibt bis in die 60er stabil oder nimmt sogar zu."},{"key":"percentile","term":"Perzentil","def":"Das Perzentil gibt an, welcher Prozentsatz der Menschen denselben oder einen niedrigeren Wert erzielt. Ein IQ von 130 entspricht dem 98. Perzentil – man liegt also über 98 % der Bevölkerung."},{"key":"standard-deviation","term":"Standardabweichung","def":"Die Standardabweichung beschreibt, wie stark die Werte um den Mittelwert streuen. Bei der Wechsler-Skala beträgt sie 15 IQ-Punkte, sodass etwa 68 % aller Menschen zwischen 85 und 115 liegen."},{"key":"normal-distribution","term":"Normalverteilung","def":"Die Normalverteilung ist die glockenförmige Kurve, der IQ-Werte folgen. Die meisten Ergebnisse häufen sich nahe dem Mittelwert von 100, während sehr hohe und sehr niedrige Werte selten sind."},{"key":"mean","term":"Mittelwert","def":"Der Mittelwert ist der statistische Durchschnitt. Beim IQ ist er per Definition auf 100 festgelegt, sodass dieser Wert genau die Mitte der Bevölkerung markiert."},{"key":"standardization","term":"Standardisierung","def":"Standardisierung bedeutet, einen Test an einer großen, repräsentativen Stichprobe zu eichen. Erst dadurch lässt sich ein Einzelergebnis sinnvoll mit der Bevölkerung vergleichen und in IQ-Punkte umrechnen."},{"key":"age-norming","term":"Altersnormierung","def":"Bei der Altersnormierung wird ein Ergebnis stets mit dem der Gleichaltrigen verglichen. Dadurch liegt der Durchschnitt in jeder Altersgruppe bei 100, obwohl sich die rohen Leistungen über die Lebensspanne verändern."},{"key":"reliability","term":"Reliabilität (Zuverlässigkeit)","def":"Die Reliabilität gibt an, wie konsistent und wiederholbar ein Test misst. Ein zuverlässiger Test liefert bei wiederholter Anwendung ähnliche Ergebnisse; ein gängiges Maß dafür ist Cronbachs Alpha."},{"key":"validity","term":"Validität (Gültigkeit)","def":"Die Validität zeigt, ob ein Test tatsächlich das misst, was er zu messen vorgibt. Ein IQ-Test ist nur dann gültig, wenn seine Ergebnisse wirklich kognitive Fähigkeiten erfassen und nicht etwa nur Übungseffekte."},{"key":"raven-matrices","term":"Ravens progressive Matrizen","def":"Ravens progressive Matrizen sind ein nonverbaler Test, bei dem man fehlende Teile eines Musters logisch ergänzt. Er gilt als eines der reinsten Maße für fluide Intelligenz und den Generalfaktor g."},{"key":"chc-theory","term":"CHC-Theorie (Cattell-Horn-Carroll)","def":"Die CHC-Theorie nach Cattell, Horn und Carroll ist das heute führende Modell der kognitiven Fähigkeiten. Sie ordnet g, breite Fähigkeiten wie fluide und kristalline Intelligenz sowie zahlreiche enge Teilfähigkeiten hierarchisch an."},{"key":"wechsler","term":"Wechsler-Tests (WAIS/WISC)","def":"Die Wechsler-Tests (WAIS für Erwachsene, WISC für Kinder) gelten als der klinische Goldstandard der IQ-Diagnostik. Sie nutzen eine Standardabweichung von 15 und werden von Fachleuten individuell durchgeführt."},{"key":"stanford-binet","term":"Stanford-Binet-Test","def":"Der Stanford-Binet ist einer der ältesten und bis heute genutzten standardisierten IQ-Tests. Er verwendet eine Standardabweichung von 16, weshalb seine hohen Werte nicht direkt mit der Wechsler-Skala (SD 15) vergleichbar sind."},{"key":"mensa","term":"Mensa","def":"Mensa ist die weltweit bekannteste Hochbegabten-Gesellschaft. Die Aufnahme setzt ein Ergebnis im 98. Perzentil voraus, also einen IQ von etwa 130 – die besten 2 % der Bevölkerung."},{"key":"flynn-effect","term":"Flynn-Effekt","def":"Der Flynn-Effekt bezeichnet den Anstieg der durchschnittlichen IQ-Leistungen im 20. Jahrhundert um rund 3 Punkte pro Jahrzehnt. Deshalb müssen Tests regelmäßig neu normiert werden, damit der Durchschnitt bei 100 bleibt."},{"key":"gifted","term":"Hochbegabung","def":"Als hochbegabt gilt üblicherweise, wer einen IQ von 130 oder höher erreicht – das entspricht den besten rund 2 % der Bevölkerung. Diese Schwelle ist zugleich die typische Aufnahmegrenze für Mensa."},{"key":"working-memory","term":"Arbeitsgedächtnis","def":"Das Arbeitsgedächtnis ist die Fähigkeit, Informationen kurzzeitig zu behalten und gleichzeitig zu verarbeiten. Es hängt eng mit dem logischen Schlussfolgern zusammen und ist ein wichtiger Bestandteil der fluiden Intelligenz."},{"key":"processing-speed","term":"Verarbeitungsgeschwindigkeit","def":"Die Verarbeitungsgeschwindigkeit beschreibt, wie schnell jemand einfache kognitive Aufgaben korrekt erledigt. Sie ist eine eigenständige Komponente der Intelligenz und fließt in moderne IQ-Tests als eigener Index ein."},{"key":"intellectual-disability","term":"Intelligenzminderung","def":"Eine Intelligenzminderung liegt vor, wenn der IQ deutlich unter dem Durchschnitt liegt (etwa 70 oder darunter) und zugleich Einschränkungen im Alltag bestehen. Beide Kriterien – Testwert und Anpassungsfähigkeit – müssen für die Diagnose erfüllt sein."}],"title":"IQ-Glossar & Fachbegriffe","sub":"Klare, kurze Definitionen der wichtigsten Begriffe rund um IQ und Intelligenztests."},"es":{"terms":[{"key":"iq","term":"Cociente intelectual (CI)","def":"El cociente intelectual es una puntuación estandarizada de la capacidad cognitiva, fijada con una media de 100 y una desviación estándar de 15. Sitúa el rendimiento de una persona en relación con el de la población general."},{"key":"deviation-iq","term":"CI de desviación","def":"El CI de desviación es el modelo moderno de cálculo: CI = 100 + 15 × z respecto a las personas de la misma edad. Sustituyó al CI de razón y es el que usan pruebas como Wechsler y Stanford-Binet."},{"key":"ratio-iq","term":"CI de razón","def":"El CI de razón es el método histórico que dividía la edad mental entre la edad cronológica y lo multiplicaba por 100 (CI = EM ÷ EC × 100). Se usaba en niños, pero hoy está obsoleto y se reemplazó por el CI de desviación."},{"key":"g-factor","term":"Factor g (inteligencia general)","def":"El factor g es la inteligencia general: el factor común que subyace al rendimiento en todas las tareas cognitivas. Explica por qué quien destaca en una habilidad mental tiende a destacar también en otras."},{"key":"fluid-intelligence","term":"Inteligencia fluida (Gf)","def":"La inteligencia fluida es la capacidad de razonar y resolver problemas nuevos sin apoyarse en conocimientos previos. Alcanza su punto máximo entre los 20 y los 25 años y declina lentamente después."},{"key":"crystallized-intelligence","term":"Inteligencia cristalizada (Gc)","def":"La inteligencia cristalizada es el conocimiento, el vocabulario y las habilidades acumulados a lo largo de la vida. A diferencia de la fluida, sigue aumentando hasta bien entrados los 60 años."},{"key":"percentile","term":"Percentil","def":"El percentil indica el porcentaje de personas a las que igualas o superas con tu puntuación. Por ejemplo, un CI en el percentil 98 significa que rindes igual o mejor que el 98 % de la población."},{"key":"standard-deviation","term":"Desviación estándar","def":"La desviación estándar mide cuánto se dispersan las puntuaciones en torno a la media. En la escala Wechsler la desviación estándar del CI es de 15, de modo que 115 está a una desviación por encima de la media."},{"key":"normal-distribution","term":"Distribución normal (campana de Gauss)","def":"La distribución normal es la curva en forma de campana que siguen las puntuaciones de CI: la mayoría se agrupan cerca de la media y los valores extremos son cada vez más raros. Es simétrica en torno a 100."},{"key":"mean","term":"Media","def":"La media es el valor promedio de un conjunto de puntuaciones. Por definición, la media del CI es 100, el punto central exacto de la distribución."},{"key":"standardization","term":"Estandarización (tipificación)","def":"La estandarización es el proceso de calibrar una prueba con una muestra amplia y representativa de la población. Así se establecen los baremos que permiten comparar la puntuación individual con la del grupo de referencia."},{"key":"age-norming","term":"Baremación por edad","def":"La baremación por edad consiste en puntuar a cada persona frente a sus pares de la misma edad, de modo que la media sea 100 en todas las edades. Por eso un CI no \"baja\" con los años pese al declive de algunas capacidades."},{"key":"reliability","term":"Fiabilidad","def":"La fiabilidad indica hasta qué punto una prueba arroja resultados consistentes y repetibles. Suele cuantificarse con índices como el alfa de Cronbach; un test fiable da puntuaciones estables al repetirlo."},{"key":"validity","term":"Validez","def":"La validez es el grado en que una prueba mide realmente lo que afirma medir. Un test de CI válido debe evaluar la capacidad cognitiva y predecir resultados relacionados, no otros factores ajenos."},{"key":"raven-matrices","term":"Matrices Progresivas de Raven","def":"Las Matrices Progresivas de Raven son una prueba no verbal de razonamiento con patrones que evalúa la inteligencia fluida (factor g). Al no depender del idioma ni de conocimientos previos, se considera relativamente libre de sesgo cultural."},{"key":"chc-theory","term":"Teoría CHC (Cattell-Horn-Carroll)","def":"La teoría de Cattell-Horn-Carroll es el modelo dominante de las capacidades cognitivas. Organiza la inteligencia en tres niveles: el factor g general, amplias aptitudes (como Gf y Gc) y habilidades específicas."},{"key":"wechsler","term":"Escalas Wechsler (WAIS/WISC)","def":"Las escalas Wechsler (WAIS en adultos y WISC en niños) son las pruebas clínicas de CI de referencia, con una desviación estándar de 15. Las administra un profesional y son el estándar de oro de la evaluación cognitiva."},{"key":"stanford-binet","term":"Stanford-Binet","def":"La Stanford-Binet es una de las primeras pruebas de inteligencia estandarizadas y aún en uso. A diferencia de Wechsler, utiliza una desviación estándar de 16."},{"key":"mensa","term":"Mensa","def":"Mensa es la sociedad de alto CI más conocida del mundo. Para ingresar hay que situarse en el percentil 98 o superior, es decir, dentro del 2 % de mayor puntuación de la población."},{"key":"flynn-effect","term":"Efecto Flynn","def":"El efecto Flynn es el aumento sostenido del CI medio a lo largo del siglo XX, de aproximadamente 3 puntos por década. Obliga a reestandarizar periódicamente las pruebas para que la media se mantenga en 100."},{"key":"gifted","term":"Superdotación","def":"La superdotación se asocia normalmente a un CI de 130 o más, lo que corresponde al 2 % superior de la población (percentil 98). Es el umbral habitual para programas educativos de altas capacidades."},{"key":"working-memory","term":"Memoria de trabajo","def":"La memoria de trabajo es la capacidad de retener y manipular información durante breves instantes. Está estrechamente ligada al razonamiento fluido y es un componente clave de las pruebas de CI."},{"key":"processing-speed","term":"Velocidad de procesamiento","def":"La velocidad de procesamiento es la rapidez con que se ejecutan tareas cognitivas simples. Es una de las aptitudes amplias del modelo CHC y contribuye al rendimiento general de CI."},{"key":"intellectual-disability","term":"Discapacidad intelectual","def":"La discapacidad intelectual implica un CI marcadamente por debajo de la media (en torno a 70 o menos) junto con limitaciones en la conducta adaptativa. El diagnóstico exige ambos criterios, no solo la puntuación."}],"title":"Glosario de CI: términos clave","sub":"Definiciones claras y precisas de los conceptos esenciales del CI y la inteligencia."},"ja":{"terms":[{"key":"iq","term":"IQ（知能指数）","def":"IQ（知能指数）とは、認知能力を標準化して表す得点で、平均100・標準偏差15になるよう設計されています。同年齢の集団の中で自分がどの位置にいるかを示す相対的な指標です。"},{"key":"deviation-iq","term":"偏差IQ","def":"偏差IQとは、同年齢の集団と比較して「100 + 15×z得点」で算出する現代のIQ方式です。古い比率IQに代わって、ウェクスラー式をはじめ今日のほぼすべての知能検査で標準として用いられています。"},{"key":"ratio-iq","term":"比率IQ","def":"比率IQとは、「精神年齢 ÷ 生活年齢 × 100」で求める歴史的なIQ算出法で、おもに子どもに用いられました。成人では精神年齢が頭打ちになり破綻するため、現在は偏差IQに置き換えられています。"},{"key":"g-factor","term":"g因子（一般知能）","def":"g因子（一般知能、g）とは、さまざまな認知課題の成績に共通して現れる中心的な能力のことです。異なる知能検査の得点が互いに正の相関を示す事実から導かれ、IQが測ろうとする中核とされています。"},{"key":"fluid-intelligence","term":"流動性知能（Gf）","def":"流動性知能（Gf）とは、未知の問題をその場で論理的に推論し解決する能力で、知識に依存しません。20代前半〜半ばでピークを迎え、その後はゆるやかに低下していきます。"},{"key":"crystallized-intelligence","term":"結晶性知能（Gc）","def":"結晶性知能（Gc）とは、語彙や一般知識など、経験を通じて蓄積された知識を活用する能力です。流動性知能とは対照的に60代頃まで上昇を続けるのが特徴です。"},{"key":"percentile","term":"パーセンタイル（百分位）","def":"パーセンタイル（百分位）とは、自分の得点が全体の何%の人と同等以上かを示す値です。たとえば90パーセンタイルなら、上位10%に入っていることを意味します。"},{"key":"standard-deviation","term":"標準偏差","def":"標準偏差とは、得点が平均からどれだけばらついているかを示す尺度です。ウェクスラー式IQの標準偏差は15で、IQ115は平均より標準偏差1つぶん上にあたります。"},{"key":"normal-distribution","term":"正規分布（ベルカーブ）","def":"正規分布（ベルカーブ）とは、左右対称の釣鐘型の分布で、多くの人の得点が平均の近くに集まり、極端に高い・低い得点ほど少なくなります。IQはこの正規分布に従うよう設計されています。"},{"key":"mean","term":"平均","def":"平均とは、全体の得点を合計して人数で割った中心的な値です。IQは定義上、平均がちょうど100になるよう標準化されています。"},{"key":"standardization","term":"標準化","def":"標準化とは、大規模で母集団を代表するサンプルに対して検査を実施し、得点の基準（平均や標準偏差）を較正する手続きです。これによって個人の得点を他者と公平に比較できます。"},{"key":"age-norming","term":"年齢別基準化（年齢ノルム）","def":"年齢別基準化とは、同じ年齢の集団を基準として得点を換算する方法で、どの年齢でも平均が100になるよう調整されます。そのため幼児でも高齢者でも、IQは同年齢の中での相対的な位置を表します。"},{"key":"reliability","term":"信頼性","def":"信頼性とは、検査の結果がどれだけ一貫し、再現可能かを示す指標です。クロンバックのα係数などで評価され、値が高いほど測定誤差が小さく安定した検査といえます。"},{"key":"validity","term":"妥当性","def":"妥当性とは、検査が測ろうとしているもの（ここでは知能）を実際に測れているかどうかを示す指標です。信頼性が高くても妥当性が低ければ、別のものを正確に測っているだけになります。"},{"key":"raven-matrices","term":"レーヴン漸進的マトリックス","def":"レーヴン漸進的マトリックスとは、図形のパターンから規則を見抜いて欠けた部分を選ぶ、言語を使わない推論検査です。流動性知能（g）を測る代表的な課題として広く用いられています。"},{"key":"chc-theory","term":"CHC理論","def":"CHC理論（キャッテル・ホーン・キャロル理論）とは、認知能力を一般知能・広域能力・狭域能力の階層で説明する、現在もっとも有力な知能の理論モデルです。多くの現代的な知能検査の設計基盤になっています。"},{"key":"wechsler","term":"ウェクスラー式知能検査（WAIS / WISC）","def":"ウェクスラー式知能検査（成人用WAIS・児童用WISC）とは、臨床現場で標準とされる代表的な個別式IQ検査です。標準偏差15を採用し、信頼性・妥当性の高さからゴールドスタンダードとされています。"},{"key":"stanford-binet","term":"スタンフォード・ビネー知能検査","def":"スタンフォード・ビネー知能検査とは、初期に確立され今日でも用いられている標準化IQ検査です。標準偏差16を採用しており、ウェクスラー式（SD15）とは尺度がわずかに異なります。"},{"key":"mensa","term":"メンサ","def":"メンサとは、高IQ者の国際的な団体で、入会基準は98パーセンタイル（上位2%）です。これはおおむねIQ130以上に相当します。"},{"key":"flynn-effect","term":"フリン効果","def":"フリン効果とは、20世紀を通じて各国で平均IQが上昇し続けた現象を指します。おおよそ10年あたり3ポイントのペースで上がっており、栄養・教育・環境の改善などが要因と考えられています。"},{"key":"gifted","term":"ギフテッド（英才）","def":"ギフテッド（英才）とは、一般にIQ130以上、すなわち上位およそ2%にあたる水準を指します。多くの英才教育プログラムでこの基準が用いられます。"},{"key":"working-memory","term":"ワーキングメモリ（作業記憶）","def":"ワーキングメモリ（作業記憶）とは、情報を短時間保持しながら同時に処理・操作する能力です。流動性推論と強く結びついており、IQ検査の重要な構成要素のひとつです。"},{"key":"processing-speed","term":"処理速度","def":"処理速度とは、単純な認知課題をどれだけ素早く正確にこなせるかを示す能力です。ウェクスラー式などの主要なIQ検査で測定される指標のひとつです。"},{"key":"intellectual-disability","term":"知的障害","def":"知的障害とは、IQがおおむね70以下と平均を大きく下回り、かつ日常生活における適応行動にも明確な制約がある状態を指します。診断にはIQだけでなく適応機能の評価も必須です。"}],"title":"IQ用語集","sub":"知能とIQ検査にまつわる重要用語を、正確かつ簡潔に解説します。"},"fr":{"terms":[{"key":"iq","term":"Quotient intellectuel (QI)","def":"Le QI est un score standardisé des capacités cognitives, calibré sur une moyenne de 100 et un écart-type de 15. Il situe une personne par rapport à l'ensemble de la population."},{"key":"deviation-iq","term":"QI par écart (QI de déviation)","def":"Le QI moderne se calcule comme 100 + 15 × z, où z mesure l'écart d'une personne par rapport à ses pairs du même âge. Cette méthode a remplacé l'ancien QI par rapport (âge mental)."},{"key":"ratio-iq","term":"QI par rapport (QI ratio)","def":"Méthode historique réservée aux enfants : QI = (âge mental ÷ âge réel) × 100. Elle est aujourd'hui abandonnée au profit du QI par écart, plus fiable chez l'adulte."},{"key":"g-factor","term":"Facteur g (intelligence générale)","def":"Le facteur g est l'aptitude générale commune à toutes les capacités cognitives, mise en évidence par leurs corrélations. C'est ce que les tests de QI cherchent avant tout à estimer."},{"key":"fluid-intelligence","term":"Intelligence fluide (Gf)","def":"L'intelligence fluide est la capacité à raisonner et résoudre des problèmes nouveaux, indépendamment des connaissances acquises. Elle atteint son sommet au début ou au milieu de la vingtaine, puis décline lentement."},{"key":"crystallized-intelligence","term":"Intelligence cristallisée (Gc)","def":"L'intelligence cristallisée regroupe les connaissances et le vocabulaire accumulés au fil de l'expérience. Elle continue de progresser jusque dans la soixantaine."},{"key":"percentile","term":"Centile (percentile)","def":"Le centile indique le pourcentage de personnes que vous égalez ou dépassez. Un QI au 98e centile signifie que vous faites mieux que 98 % de la population."},{"key":"standard-deviation","term":"Écart-type","def":"L'écart-type mesure la dispersion des scores autour de la moyenne. Sur l'échelle de Wechsler, il vaut 15 points de QI."},{"key":"normal-distribution","term":"Loi normale (courbe en cloche)","def":"La loi normale est la courbe en cloche selon laquelle se répartissent les scores de QI : la plupart se regroupent près de la moyenne, et les valeurs extrêmes sont rares."},{"key":"mean","term":"Moyenne","def":"La moyenne est la valeur centrale d'une distribution. Pour le QI, elle est fixée à 100 par définition."},{"key":"standardization","term":"Étalonnage (standardisation)","def":"L'étalonnage consiste à calibrer un test sur un large échantillon représentatif de la population. Il garantit que les scores ont une signification comparable d'une personne à l'autre."},{"key":"age-norming","term":"Étalonnage par âge","def":"L'étalonnage par âge compare chaque personne à ses pairs du même âge, de sorte que la moyenne reste 100 à tout âge. C'est pourquoi un score de QI ne baisse pas mécaniquement avec les années."},{"key":"reliability","term":"Fidélité (fiabilité)","def":"La fidélité désigne la cohérence et la reproductibilité des résultats d'un test. On l'évalue par exemple avec le coefficient alpha de Cronbach."},{"key":"validity","term":"Validité","def":"La validité indique si un test mesure réellement ce qu'il prétend mesurer. Un test peut être fidèle sans être valide, mais pas l'inverse."},{"key":"raven-matrices","term":"Matrices progressives de Raven","def":"Les matrices de Raven sont un test non verbal où il faut compléter une suite logique de motifs. Elles mesurent l'intelligence fluide (facteur g) sans recourir au langage."},{"key":"chc-theory","term":"Théorie CHC (Cattell-Horn-Carroll)","def":"La théorie de Cattell-Horn-Carroll est le modèle de référence des capacités cognitives. Elle organise l'intelligence en un facteur général (g) et de grandes aptitudes comme Gf et Gc."},{"key":"wechsler","term":"Échelles de Wechsler (WAIS/WISC)","def":"Les échelles de Wechsler (WAIS pour les adultes, WISC pour les enfants) sont les tests de QI cliniques de référence, étalonnés avec un écart-type de 15."},{"key":"stanford-binet","term":"Échelle de Stanford-Binet","def":"La Stanford-Binet est l'un des premiers tests de QI standardisés, encore utilisé aujourd'hui. Son écart-type est de 16, légèrement différent de celui de Wechsler."},{"key":"mensa","term":"Mensa","def":"Mensa est une association réservée aux hauts QI : l'admission exige un score au 98e centile, soit les 2 % supérieurs de la population (environ 130 sur l'échelle de Wechsler)."},{"key":"flynn-effect","term":"Effet Flynn","def":"L'effet Flynn désigne la hausse du QI moyen observée au cours du XXe siècle, de l'ordre de 3 points par décennie. Il oblige à réétalonner régulièrement les tests."},{"key":"gifted","term":"Haut potentiel intellectuel (HPI)","def":"Le haut potentiel correspond généralement à un QI de 130 ou plus, soit environ les 2 % supérieurs de la population. C'est le même seuil que l'admission à Mensa."},{"key":"working-memory","term":"Mémoire de travail","def":"La mémoire de travail est la capacité à retenir et manipuler brièvement de l'information. Elle est étroitement liée au raisonnement fluide."},{"key":"processing-speed","term":"Vitesse de traitement","def":"La vitesse de traitement mesure la rapidité avec laquelle on exécute des tâches cognitives simples. C'est l'une des grandes composantes évaluées par les tests de QI."},{"key":"intellectual-disability","term":"Déficience intellectuelle","def":"La déficience intellectuelle se caractérise par un QI nettement inférieur à la moyenne (environ 70 ou moins) associé à des limitations du fonctionnement adaptatif au quotidien."}],"title":"Glossaire du QI : définitions","sub":"Tous les termes clés du QI et de la psychométrie, expliqués clairement."},"pt":{"terms":[{"key":"iq","term":"QI (Quociente de Inteligência)","def":"O QI é uma pontuação padronizada que estima a capacidade cognitiva geral de uma pessoa em comparação com a população. Na escala mais usada, a média é 100 e o desvio-padrão é 15."},{"key":"deviation-iq","term":"QI de desvio","def":"O QI de desvio é o cálculo moderno do QI, definido como 100 + 15 × z, ou seja, baseado em quanto a pontuação se afasta da média de pessoas da mesma idade. Substituiu o antigo QI de razão por ser estatisticamente mais robusto."},{"key":"ratio-iq","term":"QI de razão","def":"O QI de razão é o cálculo histórico do QI, obtido pela idade mental dividida pela idade cronológica e multiplicado por 100. Funcionava razoavelmente para crianças, mas falhava em adultos e foi abandonado em favor do QI de desvio."},{"key":"g-factor","term":"Fator g (inteligência geral)","def":"O fator g é a inteligência geral, ou seja, o fator comum que está por trás do desempenho em diferentes tarefas cognitivas. Foi identificado pela observação de que pessoas boas em uma habilidade mental tendem a ser boas em outras."},{"key":"fluid-intelligence","term":"Inteligência fluida (Gf)","def":"A inteligência fluida é a capacidade de raciocinar e resolver problemas novos sem depender de conhecimento prévio. Atinge o pico no início e meados dos 20 anos e declina lentamente com a idade."},{"key":"crystallized-intelligence","term":"Inteligência cristalizada (Gc)","def":"A inteligência cristalizada é o conhecimento, o vocabulário e as habilidades acumuladas ao longo da vida. Tende a aumentar até os 60 anos ou mais, ao contrário da inteligência fluida."},{"key":"percentile","term":"Percentil","def":"O percentil indica a porcentagem de pessoas cuja pontuação é igual ou inferior à sua. Por exemplo, estar no percentil 98 significa que você pontuou igual ou acima de 98% das pessoas."},{"key":"standard-deviation","term":"Desvio-padrão","def":"O desvio-padrão mede o quanto as pontuações se espalham em torno da média. Na escala Wechsler de QI, o desvio-padrão é 15, então uma pontuação de 115 fica um desvio acima da média."},{"key":"normal-distribution","term":"Distribuição normal","def":"A distribuição normal é a curva em forma de sino que descreve como as pontuações de QI se distribuem na população. A maioria das pessoas fica perto da média, e pontuações muito altas ou muito baixas são raras."},{"key":"mean","term":"Média","def":"A média é o valor central em torno do qual as pontuações se concentram. Por definição, a média do QI é fixada em 100."},{"key":"standardization","term":"Padronização","def":"A padronização é o processo de calibrar um teste em uma amostra grande e representativa da população. É isso que permite interpretar uma pontuação individual em relação a um grupo de referência."},{"key":"age-norming","term":"Normatização por idade","def":"A normatização por idade compara cada pessoa com colegas da mesma faixa etária, de modo que a média seja sempre 100 em qualquer idade. Por isso o QI mede a posição relativa, não a quantidade absoluta de capacidade."},{"key":"reliability","term":"Fidedignidade (confiabilidade)","def":"A fidedignidade indica o quanto um teste produz resultados consistentes e repetíveis. Costuma ser quantificada por índices como o alfa de Cronbach; quanto maior, mais estáveis são as pontuações."},{"key":"validity","term":"Validade","def":"A validade indica se um teste realmente mede aquilo que afirma medir. Um teste de QI válido deve avaliar capacidade cognitiva e prever resultados ligados a ela, e não outra coisa."},{"key":"raven-matrices","term":"Matrizes Progressivas de Raven","def":"As Matrizes Progressivas de Raven são um teste não verbal em que se completa um padrão visual escolhendo a peça que falta. Avaliam o raciocínio fluido e o fator g com pouca influência de idioma ou cultura."},{"key":"chc-theory","term":"Teoria CHC (Cattell–Horn–Carroll)","def":"A teoria CHC é o modelo dominante das habilidades cognitivas, organizando-as em uma hierarquia com o fator g no topo e amplas capacidades como inteligência fluida e cristalizada abaixo. Serve de base teórica para muitos testes modernos de QI."},{"key":"wechsler","term":"Escalas Wechsler (WAIS/WISC)","def":"As escalas Wechsler, como a WAIS para adultos e a WISC para crianças, são testes clínicos de QI considerados padrão-ouro. Usam desvio-padrão de 15 e avaliam vários domínios cognitivos."},{"key":"stanford-binet","term":"Stanford-Binet","def":"O Stanford-Binet é um dos primeiros testes de QI padronizados e ainda é usado hoje. Diferentemente das escalas Wechsler, adota um desvio-padrão de 16."},{"key":"mensa","term":"Mensa","def":"A Mensa é a maior sociedade de alto QI do mundo, e o ingresso exige uma pontuação no percentil 98, ou seja, entre os 2% mais altos. Isso corresponde a cerca de 130 ou mais na maioria das escalas."},{"key":"flynn-effect","term":"Efeito Flynn","def":"O efeito Flynn é a tendência de aumento do QI médio ao longo do século XX, da ordem de cerca de 3 pontos por década. Por isso os testes precisam ser recalibrados periodicamente para manter a média em 100."},{"key":"gifted","term":"Superdotação (altas habilidades)","def":"A superdotação costuma ser definida por um QI de 130 ou mais, o que situa a pessoa entre os 2% mais altos. É uma faixa frequentemente associada a programas educacionais especiais."},{"key":"working-memory","term":"Memória de trabalho","def":"A memória de trabalho é a capacidade de reter e manipular informações por curtos períodos, como ao fazer um cálculo de cabeça. Está fortemente ligada ao raciocínio fluido."},{"key":"processing-speed","term":"Velocidade de processamento","def":"A velocidade de processamento é a rapidez com que se executam tarefas cognitivas simples e rotineiras. É uma das capacidades amplas medidas em testes de QI e tende a influenciar o desempenho geral."},{"key":"intellectual-disability","term":"Deficiência intelectual","def":"A deficiência intelectual é caracterizada por um QI significativamente abaixo da média, em geral em torno de 70 ou menos, acompanhado de limitações no funcionamento adaptativo do dia a dia. O diagnóstico exige avaliação clínica, não apenas a pontuação."}],"title":"Glossário de QI: termos explicados","sub":"Definições claras e precisas dos principais conceitos sobre QI e inteligência."},"it":{"terms":[{"key":"iq","term":"Quoziente intellettivo (QI)","def":"Il quoziente intellettivo e un punteggio standardizzato che misura le capacita cognitive generali rispetto alla popolazione, con media 100 e deviazione standard 15. Non e una misura assoluta dell'intelligenza, ma una posizione relativa rispetto ai coetanei."},{"key":"deviation-iq","term":"QI di deviazione","def":"Il QI di deviazione e il metodo moderno di calcolo: si ottiene con la formula 100 + 15 x z, dove z indica di quante deviazioni standard ci si discosta dalla media dei coetanei. Ha sostituito il vecchio QI di rapporto perche e valido a ogni eta."},{"key":"ratio-iq","term":"QI di rapporto","def":"Il QI di rapporto e il metodo storico: eta mentale diviso eta cronologica, moltiplicato per 100. Usato originariamente per i bambini, e oggi superato dal QI di deviazione perche perde di significato in eta adulta."},{"key":"g-factor","term":"Fattore g (intelligenza generale)","def":"Il fattore g e l'intelligenza generale, ossia la capacita comune che spiega la correlazione tra prestazioni in compiti cognitivi diversi. Chi rende bene in un'area tende a rendere bene anche nelle altre, e questo nucleo condiviso e proprio il fattore g."},{"key":"fluid-intelligence","term":"Intelligenza fluida (Gf)","def":"L'intelligenza fluida e la capacita di ragionare e risolvere problemi nuovi senza fare affidamento sulle conoscenze acquisite. Raggiunge il picco tra i 20 e i 25 anni e poi tende a diminuire gradualmente con l'eta."},{"key":"crystallized-intelligence","term":"Intelligenza cristallizzata (Gc)","def":"L'intelligenza cristallizzata e l'insieme delle conoscenze, del vocabolario e delle competenze accumulate con l'esperienza e lo studio. A differenza di quella fluida, continua a crescere fino ai 60 anni e oltre."},{"key":"percentile","term":"Percentile","def":"Il percentile indica la percentuale di persone che ottiene un punteggio pari o inferiore al tuo. Un percentile 98, per esempio, significa che superi o eguagli il 98% della popolazione."},{"key":"standard-deviation","term":"Deviazione standard","def":"La deviazione standard misura quanto i punteggi si disperdono attorno alla media. Sulla scala Wechsler il QI ha una deviazione standard di 15, quindi circa il 68% delle persone ottiene un punteggio tra 85 e 115."},{"key":"normal-distribution","term":"Distribuzione normale (curva a campana)","def":"La distribuzione normale e la curva a campana che descrive come si distribuiscono i punteggi di QI nella popolazione. La maggior parte dei valori si concentra vicino alla media, mentre i punteggi molto alti o molto bassi sono rari e simmetrici."},{"key":"mean","term":"Media","def":"La media e il valore medio dei punteggi. Nei test di QI la media e fissata per definizione a 100, valore attorno al quale si distribuisce la maggioranza della popolazione."},{"key":"standardization","term":"Standardizzazione","def":"La standardizzazione e la procedura con cui un test viene calibrato su un ampio campione rappresentativo della popolazione. Serve a definire le norme di riferimento affinche i punteggi individuali siano confrontabili e interpretabili."},{"key":"age-norming","term":"Normalizzazione per eta","def":"La normalizzazione per eta consiste nel confrontare il punteggio di una persona con quello dei propri coetanei, anziche con tutta la popolazione. In questo modo il punteggio medio resta 100 a ogni eta, compensando i naturali cambiamenti cognitivi nel tempo."},{"key":"reliability","term":"Affidabilita (attendibilita)","def":"L'affidabilita indica quanto un test produce risultati coerenti e ripetibili nel tempo e tra le sue parti. Si quantifica con indici come l'alfa di Cronbach: piu il valore e alto, piu il test misura in modo stabile."},{"key":"validity","term":"Validita","def":"La validita esprime se un test misura davvero cio che dichiara di misurare. Un test di QI valido valuta effettivamente le capacita cognitive e non, per esempio, la sola familiarita con il tipo di domande."},{"key":"raven-matrices","term":"Matrici progressive di Raven","def":"Le matrici progressive di Raven sono un test non verbale che misura l'intelligenza fluida attraverso il completamento di sequenze di figure secondo regole logiche. Essendo prive di linguaggio, sono tra le misure piu pure del fattore g."},{"key":"chc-theory","term":"Teoria di Cattell-Horn-Carroll (CHC)","def":"La teoria CHC e il modello oggi piu accreditato delle abilita cognitive. Organizza l'intelligenza su piu livelli: il fattore g generale al vertice, ampie abilita come quella fluida e cristallizzata al livello intermedio, e numerose abilita specifiche alla base."},{"key":"wechsler","term":"Scale Wechsler (WAIS/WISC)","def":"Le scale Wechsler, WAIS per gli adulti e WISC per i bambini, sono i test di QI clinici considerati lo standard di riferimento. Adottano una deviazione standard di 15 e vengono somministrati individualmente da professionisti."},{"key":"stanford-binet","term":"Stanford-Binet","def":"La Stanford-Binet e uno dei primi test di QI standardizzati, tuttora in uso nelle sue versioni aggiornate. Storicamente impiega una deviazione standard di 16, leggermente diversa dai 15 delle scale Wechsler."},{"key":"mensa","term":"Mensa","def":"Mensa e la principale societa internazionale per persone ad alto QI. L'ammissione richiede un punteggio al 98esimo percentile, cioe rientrare nel 2% piu alto della popolazione."},{"key":"flynn-effect","term":"Effetto Flynn","def":"L'effetto Flynn e l'aumento progressivo del QI medio osservato nel corso del XX secolo, pari a circa 3 punti per decennio. E attribuito a fattori come migliore nutrizione, istruzione e familiarita con i test, e impone periodiche ritarature delle norme."},{"key":"gifted","term":"Plusdotazione (alto potenziale cognitivo)","def":"La plusdotazione indica tipicamente un QI di 130 o superiore, cioe il 2% circa piu alto della popolazione. Identifica persone con capacita cognitive significativamente al di sopra della media."},{"key":"working-memory","term":"Memoria di lavoro","def":"La memoria di lavoro e la capacita di trattenere e manipolare brevemente le informazioni mentre si svolge un compito. E strettamente collegata al ragionamento fluido ed e una componente chiave delle prestazioni cognitive."},{"key":"processing-speed","term":"Velocita di elaborazione","def":"La velocita di elaborazione e la rapidita con cui si eseguono compiti cognitivi semplici e automatici. Una maggiore velocita libera risorse mentali per compiti piu complessi e contribuisce al punteggio complessivo di QI."},{"key":"intellectual-disability","term":"Disabilita intellettiva","def":"La disabilita intellettiva e una condizione caratterizzata da un QI significativamente inferiore alla media, intorno a 70 o meno, accompagnato da limitazioni nelle capacita adattive della vita quotidiana. La diagnosi richiede entrambi i criteri, non il solo punteggio."}],"title":"Glossario del QI","sub":"Definizioni chiare e accurate dei principali termini su QI, test e intelligenza."},"id":{"terms":[{"key":"iq","term":"IQ (Intelligence Quotient)","def":"IQ adalah skor terstandar yang menggambarkan kemampuan kognitif seseorang dibandingkan populasi umum, dengan rata-rata 100 dan simpangan baku 15. Skor ini menempatkan posisi Anda relatif terhadap orang lain, bukan jumlah jawaban benar secara mentah."},{"key":"deviation-iq","term":"IQ Deviasi","def":"IQ deviasi adalah cara penghitungan IQ modern yang membandingkan skor Anda dengan kelompok seusia, memakai rumus 100 + 15 x nilai-z. Metode ini menggantikan rasio usia mental lama dan dipakai pada tes baku seperti Wechsler."},{"key":"ratio-iq","term":"IQ Rasio","def":"IQ rasio adalah metode historis yang menghitung IQ sebagai usia mental dibagi usia kronologis dikali 100, terutama untuk anak. Metode ini sudah ditinggalkan karena tidak akurat untuk orang dewasa dan digantikan IQ deviasi."},{"key":"g-factor","term":"Faktor g (Inteligensi Umum)","def":"Faktor g adalah inteligensi umum, yaitu kemampuan dasar bersama yang mendasari kinerja di hampir semua tugas kognitif. Konsep ini menjelaskan mengapa orang yang unggul pada satu jenis tes cenderung unggul pada jenis tes lainnya."},{"key":"fluid-intelligence","term":"Inteligensi Cair (Gf)","def":"Inteligensi cair (Gf) adalah kemampuan menalar dan memecahkan masalah baru tanpa bergantung pada pengetahuan yang sudah dipelajari. Kemampuan ini memuncak pada usia awal hingga pertengahan 20-an lalu perlahan menurun."},{"key":"crystallized-intelligence","term":"Inteligensi Terkristalisasi (Gc)","def":"Inteligensi terkristalisasi (Gc) adalah akumulasi pengetahuan, kosakata, dan keterampilan yang dipelajari sepanjang hidup. Berbeda dari inteligensi cair, kemampuan ini terus meningkat hingga usia 60-an."},{"key":"percentile","term":"Persentil","def":"Persentil menunjukkan persentase orang yang skornya sama dengan atau di bawah skor Anda. Misalnya, IQ 130 berada pada persentil ke-98, artinya Anda mengungguli sekitar 98 persen populasi."},{"key":"standard-deviation","term":"Simpangan Baku","def":"Simpangan baku mengukur seberapa jauh skor menyebar dari rata-rata. Pada skala Wechsler, satu simpangan baku IQ sama dengan 15 poin, sehingga IQ 115 berarti satu simpangan baku di atas rata-rata."},{"key":"normal-distribution","term":"Distribusi Normal","def":"Distribusi normal adalah kurva lonceng yang menggambarkan sebaran skor IQ di populasi, di mana sebagian besar orang berkumpul di dekat rata-rata 100. Semakin jauh dari rata-rata, semakin sedikit orang yang memperoleh skor tersebut."},{"key":"mean","term":"Rata-rata (Mean)","def":"Rata-rata adalah nilai tengah dari sekumpulan skor. Secara definisi, rata-rata IQ ditetapkan 100, sehingga skor itu menjadi titik acuan untuk membandingkan semua hasil."},{"key":"standardization","term":"Standardisasi","def":"Standardisasi adalah proses mengkalibrasi sebuah tes pada sampel besar yang mewakili populasi agar skornya bermakna dan dapat dibandingkan. Tanpa standardisasi, skor mentah tidak bisa diterjemahkan menjadi IQ yang andal."},{"key":"age-norming","term":"Pembakuan Menurut Usia","def":"Pembakuan menurut usia membandingkan skor Anda dengan kelompok seusia, sehingga rata-rata IQ tetap 100 pada setiap kelompok umur. Inilah sebabnya IQ tidak otomatis turun seiring bertambahnya usia."},{"key":"reliability","term":"Reliabilitas","def":"Reliabilitas adalah ukuran seberapa konsisten dan dapat diulang hasil sebuah tes. Tes yang reliabel akan memberikan skor yang serupa bila diujikan ulang, sering diukur dengan koefisien seperti alfa Cronbach."},{"key":"validity","term":"Validitas","def":"Validitas adalah sejauh mana sebuah tes benar-benar mengukur apa yang diklaimnya, misalnya apakah tes IQ memang mengukur kemampuan kognitif. Tes bisa reliabel tetapi tetap tidak valid jika mengukur hal yang keliru."},{"key":"raven-matrices","term":"Matriks Progresif Raven","def":"Matriks Progresif Raven adalah tes nonverbal yang meminta Anda menemukan pola pada deret gambar dan memilih bagian yang hilang. Tes ini dianggap sebagai pengukur murni inteligensi cair karena tidak bergantung pada bahasa atau pengetahuan."},{"key":"chc-theory","term":"Teori CHC (Cattell-Horn-Carroll)","def":"Teori CHC (Cattell-Horn-Carroll) adalah model kemampuan kognitif yang paling banyak diterima saat ini, menggabungkan faktor g umum dengan berbagai kemampuan luas seperti inteligensi cair dan terkristalisasi. Teori ini menjadi kerangka dasar bagi banyak tes IQ modern."},{"key":"wechsler","term":"Skala Wechsler (WAIS/WISC)","def":"Skala Wechsler, yaitu WAIS untuk dewasa dan WISC untuk anak, adalah tes IQ klinis baku emas dengan simpangan baku 15. Tes ini diberikan langsung oleh profesional terlatih dan mengukur beberapa ranah kognitif sekaligus."},{"key":"stanford-binet","term":"Stanford-Binet","def":"Stanford-Binet adalah salah satu tes IQ terstandar pertama yang masih digunakan hingga kini, dengan simpangan baku 16. Tes ini berperan penting dalam sejarah pengukuran inteligensi dan tetap relevan untuk penilaian klinis."},{"key":"mensa","term":"Mensa","def":"Mensa adalah perkumpulan ber-IQ tinggi yang menerima anggota dengan skor pada persentil ke-98, yaitu 2 persen teratas populasi. Pada skala SD 15, ambang ini setara dengan IQ sekitar 130."},{"key":"flynn-effect","term":"Efek Flynn","def":"Efek Flynn adalah kenaikan rata-rata skor IQ sepanjang abad ke-20, sekitar 3 poin per dekade. Karena tren ini, tes IQ perlu dibakukan ulang secara berkala agar rata-rata tetap 100."},{"key":"gifted","term":"Berbakat (Gifted)","def":"Berbakat umumnya merujuk pada IQ 130 ke atas, yaitu sekitar 2 persen populasi teratas. Identifikasi anak berbakat sering memakai ambang ini untuk menentukan kebutuhan pendidikan khusus."},{"key":"working-memory","term":"Memori Kerja","def":"Memori kerja adalah kemampuan menyimpan dan mengolah informasi dalam jangka sangat singkat, misalnya menghitung di kepala. Kemampuan ini berkaitan erat dengan penalaran cair dan menjadi salah satu komponen yang diukur tes IQ."},{"key":"processing-speed","term":"Kecepatan Pemrosesan","def":"Kecepatan pemrosesan adalah seberapa cepat Anda menyelesaikan tugas kognitif sederhana secara akurat. Kecepatan ini merupakan salah satu komponen inti IQ dan memengaruhi efisiensi belajar serta bernalar."},{"key":"intellectual-disability","term":"Disabilitas Intelektual","def":"Disabilitas intelektual ditandai dengan IQ yang jauh di bawah rata-rata, sekitar 70 atau lebih rendah, disertai keterbatasan dalam keterampilan adaptif sehari-hari. Diagnosisnya selalu mempertimbangkan fungsi adaptif, bukan skor IQ semata."}],"title":"Glosarium & Istilah IQ","sub":"Penjelasan singkat dan akurat untuk istilah-istilah penting seputar tes IQ dan psikometri."},"ru":{"terms":[{"key":"iq","term":"Коэффициент интеллекта (IQ)","def":"IQ — это стандартизированная оценка когнитивных способностей человека относительно его сверстников. По шкале Векслера среднее значение равно 100, а стандартное отклонение — 15."},{"key":"deviation-iq","term":"Девиационный IQ","def":"Девиационный IQ — современный способ расчёта по формуле 100 + 15 × z, где z показывает отклонение результата от среднего по группе сверстников того же возраста. Он заменил устаревший возрастной (отношенческий) IQ."},{"key":"ratio-iq","term":"Возрастной (отношенческий) IQ","def":"Возрастной IQ — исторический способ расчёта: умственный возраст делится на хронологический и умножается на 100. Он применялся преимущественно к детям и сегодня вытеснен девиационным IQ."},{"key":"g-factor","term":"Фактор g (общий интеллект)","def":"Фактор g — это общий интеллект, единый фактор, объясняющий, почему результаты разных когнитивных тестов положительно коррелируют между собой. Именно его в значительной мере оценивает суммарный балл IQ."},{"key":"fluid-intelligence","term":"Подвижный интеллект (Gf)","def":"Подвижный интеллект (Gf) — это способность рассуждать и решать новые задачи без опоры на прошлые знания. Он достигает пика в начале — середине двадцатых лет и затем постепенно снижается."},{"key":"crystallized-intelligence","term":"Кристаллизованный интеллект (Gc)","def":"Кристаллизованный интеллект (Gc) — это накопленные знания, словарный запас и опыт. В отличие от подвижного интеллекта, он растёт почти всю жизнь и часто повышается вплоть до 60 лет и старше."},{"key":"percentile","term":"Процентиль","def":"Процентиль показывает, какой процент людей вы опережаете или с кем равны по результату. Например, IQ 130 соответствует 98-му процентилю — это значит, что выше только около 2% населения."},{"key":"standard-deviation","term":"Стандартное отклонение","def":"Стандартное отклонение — это мера разброса результатов вокруг среднего. Для IQ по шкале Векслера оно равно 15, поэтому диапазон 85–115 охватывает примерно две трети людей."},{"key":"normal-distribution","term":"Нормальное распределение","def":"Нормальное распределение — это симметричная колоколообразная кривая, по которой распределены баллы IQ. Большинство результатов сосредоточено вблизи среднего (100), а крайне высокие и крайне низкие значения встречаются редко."},{"key":"mean","term":"Среднее значение","def":"Среднее значение — это арифметическое среднее всех результатов. Для IQ оно по определению равно 100 после калибровки теста."},{"key":"standardization","term":"Стандартизация","def":"Стандартизация — это калибровка теста на большой репрезентативной выборке, благодаря которой устанавливаются нормы и среднее значение 100. Это позволяет сравнивать индивидуальный результат с населением."},{"key":"age-norming","term":"Возрастные нормы","def":"Возрастные нормы означают, что результат сравнивается со сверстниками того же возраста, поэтому среднее значение остаётся равным 100 в любом возрасте. Это компенсирует естественные возрастные изменения когнитивных способностей."},{"key":"reliability","term":"Надёжность","def":"Надёжность — это устойчивость и воспроизводимость результатов теста при повторном прохождении. Её часто оценивают коэффициентом, например альфой Кронбаха; чем он ближе к 1, тем стабильнее тест."},{"key":"validity","term":"Валидность","def":"Валидность показывает, действительно ли тест измеряет то, что заявлено, — в данном случае интеллект. Тест может быть надёжным, но при этом невалидным, если он измеряет нечто иное."},{"key":"raven-matrices","term":"Прогрессивные матрицы Равена","def":"Прогрессивные матрицы Равена — это невербальный тест, в котором нужно выбрать недостающий элемент по закономерности рисунка. Он считается одним из наиболее чистых измерителей подвижного интеллекта (g)."},{"key":"chc-theory","term":"Теория Кеттелла — Хорна — Кэрролла (CHC)","def":"Теория CHC — это ведущая современная модель структуры когнитивных способностей. Она объединяет общий интеллект (g), широкие способности (например, Gf и Gc) и множество узких навыков в единую иерархию."},{"key":"wechsler","term":"Шкалы Векслера (WAIS/WISC)","def":"Шкалы Векслера — WAIS для взрослых и WISC для детей — это клинические тесты IQ, считающиеся золотым стандартом. Они используют среднее 100 и стандартное отклонение 15."},{"key":"stanford-binet","term":"Шкала Стэнфорд — Бине","def":"Шкала Стэнфорд — Бине — это один из первых и до сих пор применяемых стандартизированных тестов IQ. Исторически она использует стандартное отклонение 16, тогда как у шкалы Векслера оно равно 15."},{"key":"mensa","term":"Менса","def":"Менса — это международное общество людей с высоким IQ. Для вступления нужно показать результат на уровне 98-го процентиля или выше, то есть войти в верхние 2% населения."},{"key":"flynn-effect","term":"Эффект Флинна","def":"Эффект Флинна — это наблюдавшийся в XX веке рост среднего IQ примерно на 3 балла за десятилетие. Из-за него тесты периодически пересматривают, чтобы среднее оставалось равным 100."},{"key":"gifted","term":"Интеллектуальная одарённость","def":"Одарённость обычно определяют как IQ от 130 и выше, что соответствует примерно верхним 2% населения. Это тот же порог, что и для вступления в Менсу."},{"key":"working-memory","term":"Рабочая память","def":"Рабочая память — это способность недолго удерживать и одновременно обрабатывать информацию в уме. Она тесно связана с подвижным интеллектом и заметно влияет на решение сложных задач."},{"key":"processing-speed","term":"Скорость обработки информации","def":"Скорость обработки информации — это то, насколько быстро человек выполняет простые когнитивные задачи. Это одна из широких способностей в модели CHC, влияющая на общую эффективность мышления."},{"key":"intellectual-disability","term":"Интеллектуальная инвалидность (умственная отсталость)","def":"Интеллектуальная инвалидность — это значительно ниже среднего уровень интеллекта (IQ примерно 70 и ниже), сопровождающийся ограничениями в повседневной адаптации. Диагноз ставится только клинически, а не по онлайн-тесту."}],"title":"Глоссарий терминов IQ","sub":"Понятные определения ключевых понятий об интеллекте, тестах и баллах IQ."},"vi":{"terms":[{"key":"iq","term":"Chỉ số thông minh (IQ)","def":"IQ là điểm số chuẩn hóa đo năng lực nhận thức, với trung bình quy ước là 100 và độ lệch chuẩn 15. Nó cho biết vị trí tương đối của một người so với dân số cùng độ tuổi."},{"key":"deviation-iq","term":"IQ độ lệch","def":"IQ độ lệch là cách tính IQ hiện đại theo công thức 100 + 15 × z, so sánh điểm của bạn với nhóm cùng tuổi. Phương pháp này đã thay thế IQ tỉ lệ cũ và là chuẩn của mọi bài trắc nghiệm ngày nay."},{"key":"ratio-iq","term":"IQ tỉ lệ","def":"IQ tỉ lệ là cách tính IQ trong lịch sử, bằng tuổi trí tuệ chia cho tuổi thực rồi nhân 100, chủ yếu dùng cho trẻ em. Nó không còn phù hợp với người trưởng thành và đã được IQ độ lệch thay thế."},{"key":"g-factor","term":"Yếu tố g (trí thông minh chung)","def":"Yếu tố g là trí thông minh chung, thành phần chung nằm sau mọi năng lực nhận thức và giải thích vì sao người làm tốt một loại bài thường làm tốt các loại khác. Đây là khái niệm trung tâm của tâm trắc học hiện đại."},{"key":"fluid-intelligence","term":"Trí thông minh linh hoạt (Gf)","def":"Trí thông minh linh hoạt (Gf) là khả năng suy luận và giải quyết vấn đề mới mà không cần kiến thức học trước. Năng lực này đạt đỉnh vào khoảng đầu đến giữa tuổi 20 rồi giảm dần."},{"key":"crystallized-intelligence","term":"Trí thông minh kết tinh (Gc)","def":"Trí thông minh kết tinh (Gc) là kho kiến thức, từ vựng và kỹ năng tích lũy qua học tập và kinh nghiệm. Khác với trí linh hoạt, năng lực này tiếp tục tăng đến khi ngoài 60 tuổi."},{"key":"percentile","term":"Phân vị (bách phân vị)","def":"Phân vị là tỉ lệ phần trăm số người có điểm bằng hoặc thấp hơn bạn. Ví dụ, điểm ở phân vị 98 nghĩa là bạn vượt 98% dân số."},{"key":"standard-deviation","term":"Độ lệch chuẩn","def":"Độ lệch chuẩn đo mức phân tán của các điểm số quanh giá trị trung bình. Trên thang Wechsler, độ lệch chuẩn của IQ là 15, nên 15 điểm tương ứng một độ lệch chuẩn."},{"key":"normal-distribution","term":"Phân phối chuẩn (đường cong hình chuông)","def":"Phân phối chuẩn là đường cong hình chuông mô tả cách điểm IQ trải ra trong dân số. Phần lớn người tập trung gần mức trung bình 100, càng xa hai đầu càng hiếm."},{"key":"mean","term":"Giá trị trung bình","def":"Giá trị trung bình là số bình quân của một tập điểm. Theo quy ước, trung bình của IQ luôn được đặt bằng 100."},{"key":"standardization","term":"Chuẩn hóa","def":"Chuẩn hóa là quá trình hiệu chỉnh một bài trắc nghiệm trên một mẫu lớn và đại diện cho dân số. Nhờ đó điểm của mỗi người có thể so sánh công bằng theo cùng một thang chuẩn."},{"key":"age-norming","term":"Chuẩn hóa theo độ tuổi","def":"Chuẩn hóa theo độ tuổi là việc tính điểm dựa trên nhóm cùng lứa tuổi, sao cho mức trung bình luôn là 100 ở mọi độ tuổi. Vì vậy IQ phản ánh vị trí tương đối, không phải năng lực tuyệt đối thay đổi theo tuổi."},{"key":"reliability","term":"Độ tin cậy","def":"Độ tin cậy cho biết một bài trắc nghiệm cho kết quả nhất quán và ổn định đến mức nào khi đo lặp lại. Nó thường được lượng hóa bằng các chỉ số như hệ số alpha của Cronbach."},{"key":"validity","term":"Độ hiệu lực","def":"Độ hiệu lực cho biết một bài trắc nghiệm có thực sự đo đúng thứ nó tuyên bố đo hay không. Một bài có thể rất ổn định nhưng vẫn vô nghĩa nếu thiếu độ hiệu lực."},{"key":"raven-matrices","term":"Ma trận tiến triển Raven","def":"Ma trận tiến triển Raven là bài trắc nghiệm phi ngôn ngữ yêu cầu nhận ra quy luật hình ảnh để chọn mảnh còn thiếu. Đây là công cụ kinh điển đo trí thông minh linh hoạt (g)."},{"key":"chc-theory","term":"Thuyết Cattell–Horn–Carroll (CHC)","def":"Thuyết CHC là mô hình năng lực nhận thức được công nhận rộng rãi nhất hiện nay. Nó sắp xếp trí tuệ theo nhiều tầng, từ yếu tố g chung đến các năng lực rộng như Gf và Gc và các kỹ năng cụ thể hơn."},{"key":"wechsler","term":"Thang Wechsler (WAIS/WISC)","def":"Thang Wechsler gồm WAIS cho người lớn và WISC cho trẻ em, là các bài trắc nghiệm IQ lâm sàng chuẩn mực với độ lệch chuẩn 15. Đây là công cụ đánh giá trí tuệ được tin dùng nhất trong giới chuyên môn."},{"key":"stanford-binet","term":"Thang Stanford–Binet","def":"Stanford–Binet là một trong những bài trắc nghiệm IQ chuẩn hóa ra đời sớm nhất và vẫn được dùng đến nay, với độ lệch chuẩn 16. Vì độ lệch chuẩn khác Wechsler nên cùng một con số IQ có thể mang ý nghĩa hơi khác nhau."},{"key":"mensa","term":"Hội Mensa","def":"Mensa là hội của những người có IQ cao, tiêu chuẩn gia nhập là đạt phân vị 98 trở lên, tức nhóm 2% cao nhất dân số. Điều này tương ứng khoảng IQ 130 trên thang độ lệch chuẩn 15."},{"key":"flynn-effect","term":"Hiệu ứng Flynn","def":"Hiệu ứng Flynn là hiện tượng điểm IQ trung bình tăng dần suốt thế kỷ 20, vào khoảng 3 điểm mỗi thập kỷ. Vì vậy các bài trắc nghiệm phải được chuẩn hóa lại định kỳ để giữ mức trung bình ở 100."},{"key":"gifted","term":"Năng khiếu trí tuệ (thiên tư)","def":"Năng khiếu trí tuệ thường được xác định ở mức IQ từ 130 trở lên, tức nhóm khoảng 2% cao nhất dân số. Đây là ngưỡng phổ biến để nhận diện học sinh có tiềm năng vượt trội."},{"key":"working-memory","term":"Trí nhớ làm việc","def":"Trí nhớ làm việc là khả năng giữ và xử lý thông tin trong đầu trong thời gian ngắn. Nó gắn liền với trí thông minh linh hoạt và đóng vai trò then chốt trong suy luận và học tập."},{"key":"processing-speed","term":"Tốc độ xử lý","def":"Tốc độ xử lý là mức độ nhanh khi bạn thực hiện các thao tác nhận thức đơn giản và quen thuộc. Đây là một trong các thành phần được nhiều bài trắc nghiệm IQ đo lường."},{"key":"intellectual-disability","term":"Khuyết tật trí tuệ","def":"Khuyết tật trí tuệ là tình trạng IQ thấp hơn mức trung bình đáng kể, thường khoảng 70 trở xuống, kèm theo hạn chế về kỹ năng thích ứng trong sinh hoạt hằng ngày. Việc chẩn đoán cần đánh giá lâm sàng đầy đủ, không chỉ dựa vào điểm số."}],"title":"Thuật ngữ IQ","sub":"Giải thích ngắn gọn, chính xác các khái niệm cốt lõi về IQ và đo lường trí tuệ."},"hi":{"terms":[{"key":"iq","term":"बुद्धि-लब्धि (IQ)","def":"बुद्धि-लब्धि एक मानकीकृत स्कोर है जो किसी व्यक्ति की संज्ञानात्मक क्षमता को मापता है। इसका औसत 100 और मानक विचलन 15 निर्धारित है।"},{"key":"deviation-iq","term":"विचलन IQ","def":"विचलन IQ आधुनिक IQ गणना है, जिसमें स्कोर = 100 + 15×z होता है और इसकी तुलना समान आयु के लोगों से की जाती है। इसने पुरानी अनुपात-IQ पद्धति की जगह ले ली।"},{"key":"ratio-iq","term":"अनुपात IQ","def":"अनुपात IQ एक पुरानी पद्धति है जिसमें IQ = (मानसिक आयु ÷ कालानुक्रमिक आयु) × 100 निकाला जाता था। यह मुख्यतः बच्चों के लिए उपयोग होती थी और अब इसकी जगह विचलन IQ ने ले ली है।"},{"key":"g-factor","term":"सामान्य बुद्धि (g-कारक)","def":"g-कारक वह सामान्य बौद्धिक क्षमता है जो सभी संज्ञानात्मक कार्यों में समान रूप से दिखाई देती है। यह विभिन्न मानसिक परीक्षणों के परिणामों के बीच के साझा संबंध को दर्शाता है।"},{"key":"fluid-intelligence","term":"तरल बुद्धि (Gf)","def":"तरल बुद्धि नई और अपरिचित समस्याओं को तर्क से हल करने की क्षमता है, जो पूर्व ज्ञान पर निर्भर नहीं करती। यह 20 के दशक के आरंभ-मध्य में चरम पर होती है और फिर धीरे-धीरे घटती है।"},{"key":"crystallized-intelligence","term":"ठोस बुद्धि (Gc)","def":"ठोस बुद्धि जीवन भर अर्जित ज्ञान, शब्दावली और अनुभव को दर्शाती है। यह उम्र के साथ बढ़ती रहती है और प्रायः 60 के दशक तक ऊँची बनी रहती है।"},{"key":"percentile","term":"प्रतिशतांक","def":"प्रतिशतांक यह बताता है कि आपके स्कोर के बराबर या उससे नीचे कितने प्रतिशत लोग आते हैं। उदाहरण के लिए, 90वाँ प्रतिशतांक का अर्थ है कि आप 90% लोगों से बेहतर या बराबर हैं।"},{"key":"standard-deviation","term":"मानक विचलन","def":"मानक विचलन यह मापता है कि स्कोर औसत के आसपास कितने फैले हुए हैं। वेक्स्लर पैमाने पर IQ का मानक विचलन 15 होता है।"},{"key":"normal-distribution","term":"सामान्य वितरण (घंटी-वक्र)","def":"सामान्य वितरण वह घंटी के आकार का वक्र है जिसमें अधिकांश स्कोर औसत के पास इकट्ठा होते हैं और दोनों छोरों पर कम। IQ स्कोर इसी वितरण का पालन करते हैं।"},{"key":"mean","term":"औसत (माध्य)","def":"औसत किसी समूह के सभी स्कोरों का गणितीय माध्य है। परिभाषा के अनुसार IQ का औसत 100 निर्धारित किया गया है।"},{"key":"standardization","term":"मानकीकरण","def":"मानकीकरण एक बड़े और प्रतिनिधि नमूने पर परीक्षण को अंशांकित करने की प्रक्रिया है। इससे स्कोरों की तुलना का एक स्थिर और निष्पक्ष आधार बनता है।"},{"key":"age-norming","term":"आयु-आधारित मानकीकरण","def":"आयु-आधारित मानकीकरण में स्कोर की तुलना समान आयु के लोगों से की जाती है, ताकि हर आयु पर औसत 100 बना रहे। यही कारण है कि IQ स्कोर सीधे उम्र पर निर्भर नहीं करता।"},{"key":"reliability","term":"विश्वसनीयता","def":"विश्वसनीयता यह दर्शाती है कि कोई परीक्षण कितना सुसंगत और दोहराने योग्य परिणाम देता है। इसे प्रायः क्रोनबाख के अल्फा जैसे मापों से आँका जाता है।"},{"key":"validity","term":"वैधता","def":"वैधता यह बताती है कि कोई परीक्षण सचमुच उसी चीज़ को मापता है या नहीं जिसका वह दावा करता है। अधिक वैधता वाला IQ परीक्षण वास्तव में बौद्धिक क्षमता को ही मापता है।"},{"key":"raven-matrices","term":"रेवेन प्रगतिशील मैट्रिसेस","def":"रेवेन प्रगतिशील मैट्रिसेस एक अशाब्दिक पैटर्न-तर्क परीक्षण है जो तरल बुद्धि (g) को मापता है। इसमें भाषा या पूर्व ज्ञान की आवश्यकता नहीं होती, इसलिए यह संस्कृति-निरपेक्ष माना जाता है।"},{"key":"chc-theory","term":"CHC सिद्धांत","def":"कैटेल–हॉर्न–कैरोल (CHC) सिद्धांत संज्ञानात्मक क्षमताओं का सबसे प्रमुख और स्वीकृत मॉडल है। यह बुद्धि को सामान्य g तथा कई व्यापक एवं संकीर्ण क्षमताओं की संरचना के रूप में प्रस्तुत करता है।"},{"key":"wechsler","term":"वेक्स्लर परीक्षण (WAIS/WISC)","def":"वेक्स्लर परीक्षण (वयस्कों के लिए WAIS, बच्चों के लिए WISC) चिकित्सकीय IQ मापन के स्वर्ण-मानक परीक्षण हैं। इनका मानक विचलन 15 होता है।"},{"key":"stanford-binet","term":"स्टैनफर्ड-बिने परीक्षण","def":"स्टैनफर्ड-बिने एक आरंभिक और आज भी प्रयोग किया जाने वाला मानकीकृत IQ परीक्षण है। इसका मानक विचलन 16 होता है।"},{"key":"mensa","term":"मेन्सा","def":"मेन्सा एक उच्च-IQ समाज है जिसमें प्रवेश के लिए 98वें प्रतिशतांक (ऊपरी 2%) का स्कोर आवश्यक है। यह मानक IQ पैमाने पर लगभग 130 के बराबर है।"},{"key":"flynn-effect","term":"फ्लिन प्रभाव","def":"फ्लिन प्रभाव 20वीं सदी में औसत IQ स्कोर के लगातार बढ़ने की प्रवृत्ति है। यह वृद्धि प्रति दशक लगभग 3 अंक रही, जिससे परीक्षणों का समय-समय पर पुनर्मानकीकरण आवश्यक हुआ।"},{"key":"gifted","term":"प्रतिभाशाली (गिफ्टेड)","def":"प्रतिभाशाली प्रायः उस व्यक्ति को कहा जाता है जिसका IQ 130 या उससे अधिक हो। यह आबादी के ऊपरी लगभग 2% में आता है।"},{"key":"working-memory","term":"कार्यशील स्मृति","def":"कार्यशील स्मृति थोड़े समय के लिए जानकारी को मन में रखकर उस पर काम करने की क्षमता है। यह तरल तर्क से घनिष्ठ रूप से जुड़ी होती है।"},{"key":"processing-speed","term":"प्रसंस्करण गति","def":"प्रसंस्करण गति यह मापती है कि आप सरल संज्ञानात्मक कार्यों को कितनी तेज़ी से कर पाते हैं। यह बुद्धि का एक महत्वपूर्ण घटक है, विशेषकर ध्यान और प्रतिक्रिया से जुड़े कार्यों में।"},{"key":"intellectual-disability","term":"बौद्धिक अक्षमता","def":"बौद्धिक अक्षमता उस स्थिति को कहते हैं जिसमें IQ औसत से काफ़ी कम (लगभग 70 या उससे नीचे) होने के साथ-साथ दैनिक जीवन के अनुकूली कौशलों में भी सीमाएँ होती हैं। केवल कम स्कोर पर्याप्त नहीं; अनुकूली कमी भी आवश्यक है।"}],"title":"IQ शब्दावली / पारिभाषिक शब्द","sub":"बुद्धि और IQ परीक्षण से जुड़े मुख्य शब्दों की सरल, सटीक व्याख्या।"},"tr":{"terms":[{"key":"iq","term":"IQ (Zeka Bölümü)","def":"IQ, bilişsel yeteneği standart bir ölçekte ifade eden puandır; ortalaması 100, standart sapması 15 olacak şekilde tanımlanır. Bireyin performansını aynı yaş grubundaki insanlarla karşılaştırır."},{"key":"deviation-iq","term":"Sapma IQ'su","def":"Sapma IQ'su, modern IQ hesaplama yöntemidir ve 100 + 15 × z formülüyle, kişinin puanını aynı yaştaki akranlarına göre konumlandırır. Eski oran IQ'sunun yerini almıştır."},{"key":"ratio-iq","term":"Oran IQ'su","def":"Oran IQ'su, tarihsel bir hesaplama yöntemidir: zihinsel yaş, takvim yaşına bölünüp 100 ile çarpılır. Özellikle çocuklarda kullanılmış, ancak günümüzde yerini sapma IQ'suna bırakmıştır."},{"key":"g-factor","term":"g faktörü (genel zeka)","def":"g faktörü, farklı bilişsel testlerin paylaştığı ortak bileşeni temsil eden genel zekadır. Çeşitli yeteneklerdeki performansların neden birbiriyle ilişkili olduğunu açıklar."},{"key":"fluid-intelligence","term":"Akışkan zeka (Gf)","def":"Akışkan zeka (Gf), önceden öğrenilmiş bilgiye dayanmadan yeni problemleri akıl yürütme ve örüntü çözme yeteneğidir. 20'li yaşların başında-ortasında zirveye ulaşır ve ardından yavaşça azalır."},{"key":"crystallized-intelligence","term":"Kristalize zeka (Gc)","def":"Kristalize zeka (Gc), yaşam boyu biriken bilgi, kelime dağarcığı ve deneyimden oluşur. Yaşla birlikte artmayı sürdürür ve genellikle 60'lı yaşlara kadar yükselebilir."},{"key":"percentile","term":"Yüzdelik dilim","def":"Yüzdelik dilim, sizinle eşit ya da daha düşük puan alan insanların yüzdesini gösterir. Örneğin 90. yüzdelik, nüfusun %90'ından iyi performans gösterdiğiniz anlamına gelir."},{"key":"standard-deviation","term":"Standart sapma","def":"Standart sapma, puanların ortalama etrafında ne kadar yayıldığını ölçer. Wechsler ölçeğinde IQ standart sapması 15'tir."},{"key":"normal-distribution","term":"Normal dağılım","def":"Normal dağılım, çan eğrisi olarak da bilinen simetrik dağılımdır; puanların çoğu ortalamanın yakınında toplanır, uç değerler ise nadirdir. IQ puanları bu dağılıma uyacak şekilde tasarlanır."},{"key":"mean","term":"Ortalama","def":"Ortalama, bir puan grubunun aritmetik merkezidir. IQ ölçeğinde ortalama tanım gereği 100'dür."},{"key":"standardization","term":"Standardizasyon","def":"Standardizasyon, bir testin geniş ve temsili bir örneklem üzerinde kalibre edilerek puanlar için referans normlarının oluşturulması sürecidir. Bu sayede bireysel sonuçlar anlamlı şekilde karşılaştırılabilir."},{"key":"age-norming","term":"Yaşa göre normlama","def":"Yaşa göre normlama, puanların aynı yaştaki akranlara göre hesaplanmasıdır; böylece ortalama her yaş grubunda 100 olur. Bu nedenle IQ, yaşa rağmen göreli konumu yansıtır."},{"key":"reliability","term":"Güvenirlik","def":"Güvenirlik, bir testin sonuçlarının ne kadar tutarlı ve tekrarlanabilir olduğunu gösterir. Cronbach alfa gibi katsayılarla ölçülür ve yüksek değerler kararlı ölçüme işaret eder."},{"key":"validity","term":"Geçerlik","def":"Geçerlik, bir testin gerçekten ölçmeyi iddia ettiği şeyi ölçüp ölçmediğini ifade eder. Güvenilir bir test geçerli olmayabilir; ikisi farklı niteliklerdir."},{"key":"raven-matrices","term":"Raven Progresif Matrisleri","def":"Raven Progresif Matrisleri, sözel olmayan örüntü tamamlama sorularıyla akışkan zekayı (g) ölçen bir testtir. Dil ve kültürel bilgiden büyük ölçüde bağımsız olduğu için yaygın biçimde kullanılır."},{"key":"chc-theory","term":"CHC kuramı","def":"CHC (Cattell-Horn-Carroll) kuramı, bilişsel yetenekleri açıklayan günümüzün önde gelen modelidir. Genel zekayı, akışkan ve kristalize zeka gibi geniş yetenekler ile çok sayıda dar yeteneği hiyerarşik biçimde birleştirir."},{"key":"wechsler","term":"Wechsler ölçekleri (WAIS/WISC)","def":"Wechsler ölçekleri (yetişkinler için WAIS, çocuklar için WISC), klinikte altın standart kabul edilen IQ testleridir. Standart sapmaları 15'tir ve birçok bilişsel alanı kapsamlı biçimde değerlendirir."},{"key":"stanford-binet","term":"Stanford-Binet","def":"Stanford-Binet, ilk standartlaştırılmış zeka testlerinden biridir ve bugün de güncellenmiş sürümleriyle kullanılır. Bazı sürümlerinde standart sapma 16 olarak alınır."},{"key":"mensa","term":"Mensa","def":"Mensa, yüksek IQ'lu bireylerin oluşturduğu uluslararası bir topluluktur. Üyelik için 98. yüzdelik dilimde, yani nüfusun en üst %2'sinde yer almak gerekir."},{"key":"flynn-effect","term":"Flynn etkisi","def":"Flynn etkisi, 20. yüzyıl boyunca ortalama IQ puanlarının kuşaklar arasında istikrarlı biçimde yükselmesidir; yaklaşık on yılda 3 puanlık bir artış gözlenmiştir. Beslenme, eğitim ve çevresel etkenlerin katkısı olduğu düşünülür."},{"key":"gifted","term":"Üstün zekalı","def":"Üstün zekalılık genellikle 130 ve üzeri IQ ile tanımlanır; bu da nüfusun yaklaşık en üst %2'sine karşılık gelir. Tek başına IQ, üstün yeteneğin tek ölçütü olmamakla birlikte yaygın bir eşiktir."},{"key":"working-memory","term":"Çalışma belleği","def":"Çalışma belleği, bilgiyi kısa süre zihinde tutup aynı anda işleme yeteneğidir. Akışkan akıl yürütmeyle yakından ilişkilidir ve karmaşık problem çözmenin temelini oluşturur."},{"key":"processing-speed","term":"İşlem hızı","def":"İşlem hızı, basit bilişsel görevleri ne kadar hızlı ve doğru yaptığınızı ölçer. Genel bilişsel verimliliğin önemli bir bileşenidir ve diğer zihinsel süreçleri destekler."},{"key":"intellectual-disability","term":"Zihinsel yetersizlik","def":"Zihinsel yetersizlik, ortalamanın belirgin biçimde altında bir IQ (yaklaşık 70 ve altı) ile birlikte günlük yaşamda uyumsal becerilerde sınırlılıkların bulunmasıdır. Tanı, yalnızca puana değil işlevselliğe de dayanır."}],"title":"IQ Sözlüğü ve Terimleri","sub":"Zeka testlerinde sık geçen temel kavramların açık ve doğru tanımları."}};
